srcDoc.css:
#container {
  position: relative;
  width: 100%;
}

#base {
  width: 100%;
  display: block;
}

#overlay {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  pointer-events: none;
}

#base,
#overlay {
  width: 60%;
  margin-left: 20%;
}

srcDoc.js:
function renderOverlays() {
  const container = document.getElementById("overlays");
  container.innerHTML = "";
  const overlays = appsmith.model.overlays || [];
  const maxIntensity = Math.max(...overlays.map(x => x.intensity || 1), 1);
  overlays.forEach(item => {
    const img = document.createElement("img");
    img.src = item.url;
    img.style.position = "absolute";
    img.style.top = "0";
    img.style.left = "0";
    img.style.width = "60%";
    img.style.marginLeft = "20%";
    img.style.pointerEvents = "none";
    img.style.opacity = Math.max(0.25, item.intensity / maxIntensity);
    container.appendChild(img);
  });
}
appsmith.onReady(() => {
  renderOverlays();
});
appsmith.onModelChange(() => {
  renderOverlays();
});

